function LxPayCtrl:DoInnerBuy(rechargeData, tgaData)
    if rechargeData.skipTicketBuy then return false end
    local cashItem = rechargeData.cashItem
    local num = ModuleCenter.Item:GetItemCount(Item_Ids.Ticket)
    if num >= cashItem then
        ShowPanel(UiNames.TicketBuy, {rechargeData = rechargeData})
        return true
    end
    return false
end

function LxPayCtrl:DoBuy(rechargeData, tkData)
    local welfareRefId = rechargeData.welfareRefId
    rechargeData.payValue = checknumber(self:_InnerGetWelfarePayValueStr(welfareRefId))
    rechargeData.cashItem = self:_InnerGetWelfareCastItemValue(welfareRefId)
    local welfare = GameTable.WelfareActivitiesGiftRef[welfareRefId]
    if welfare then
        rechargeData.productName = welfare.name
    end

    local showName = rechargeData.showName
    if not string.isempty(showName) then
        showName = string.gsub(showName, "</size>", "")
        showName = string.gsub(showName, "<size=%w->", "")
        rechargeData.showName = showName
    end

    if self:DoInnerBuy(rechargeData, tkData) then
        return
    end
    if gLxSdkImpl then
        gLxSdkImpl:CallMethod(SdkMethod.DoPayOrderRequest,rechargeData, tkData)
    end
end


local _PayIdFmtEnums = {
    Recharge = "#a1#|1|#a2#|#a3#",
    Gift = "#a1#|2|#a2###a3###a4#|#a5#",
    Activity = "#a1#|3|#a2###a3###a4#|#a5#",
    Ticket = "#a1#|4|#a2#|#a3#",
}
--* 钻石直购类型
--* 充值参数格式:welfareId(计费点-礼包表refId)|type(1-充值钻石)|直充表refId
--local _IdFmtRecharge = "#a1#|1|#a2#"
function LxPayCtrl:BuyRecharge(params)
    local refId = params.refId
    local refData = GameTable.TopupRef[refId]

    local diamonds = 0
    local diamondList = LxDataHelper.ParseItemList(refData.baseReward)
    if diamondList then
        local diamondData = diamondList[1]
        diamonds = diamondData and diamondData.refId == Item_Ids.Diamond and diamondData.num or 0
    end
    local welfareRefId = refData.welfareRefId
    local discountWelfareRefId, discountItemRefId = CtrlCenter.Item:GetPayDiscountData(welfareRefId)
    if discountWelfareRefId then
        welfareRefId = discountWelfareRefId
    end
    local payId = string.replace(_PayIdFmtEnums.Recharge, welfareRefId, refId,discountItemRefId or 0)
    local showName = I18nText(refData.name)
    local v, n = string.gmatch(showName, "(%w+)<size=%w+>(.-)</size>")
    if v and n then
        showName = v..n
    end
    local rechargeData = {
        refId = refId,
        welfareRefId = welfareRefId,
        payType = 1,
        payId = payId,
        showName = showName,
        skipTicketBuy = refData.type == 2,
        diamonds = diamonds,
    }
    local tgaData = {}
    self:DoBuy(rechargeData,tgaData)
end

--* 购买游戏内置礼包类型
--* 充值参数格式:welfareId(计费点-礼包表refId)|type(2-内置礼包)|内置礼包类型#礼包refId
--* 1-弹窗礼包,2-商店直充礼包,3-vip礼包
--local _IdFmtGift = "#a1#|2|#a2###a3###a4#"
function LxPayCtrl:BuyGift(params)
    local refId = params.refId
    local giftType = params.giftType
    local welfareRefId = nil
    local extraId = params.extraId or 0
    local showName = ""
    if giftType == PayEnums.Gift_Vip then
        local refData = GameTable.StoreFixedRef[refId]
        welfareRefId = tonumber(refData.price)
        showName = I18nText(refData.name)
    elseif giftType == PayEnums.Gift_Pop then
        local giftCfg = GameTable.PopupPackageRef[refId]
        welfareRefId = tonumber(giftCfg.price)
        showName = I18nText(giftCfg.name)
    elseif giftType == PayEnums.Gift_Shop then
        local shopData = GameTable.ShopPublicRef[extraId]
        local refData = nil
        if shopData.shopType == 1 then
            refData = GameTable.StoreFixedRef[refId]
        else
            refData = GameTable.StoreRandomRef[refId]
        end
        showName = I18nText(refData.name)
        welfareRefId = tonumber(refData.price)
    elseif giftType == PayEnums.Gift_MonthCard then
        local refData = GameTable.MonthlyCardRef[refId]
        local cardData = GameTable.MonthlyCardRechargeRef[extraId]
        welfareRefId = tonumber(cardData.price)
        showName = I18nText(refData.name)
    else
        return
    end
    if welfareRefId == nil then
        if LOG_INFO_ENABLED then
            print("pay error ---->>>>")
            LogError("refId ="..tostring(refId).." | giftType="..tostring(giftType))
        end
        return
    end
    local discountWelfareRefId, discountItemRefId = CtrlCenter.Item:GetPayDiscountData(welfareRefId)
    if discountWelfareRefId then
        welfareRefId = discountWelfareRefId
    end
    local payId = string.replace(_PayIdFmtEnums.Gift, welfareRefId, giftType, refId, extraId, discountItemRefId or 0)
    local rechargeData = {
        refId = refId,
        extraId = extraId,
        giftType = giftType,
        welfareRefId = welfareRefId,
        payType = 2,
        payId = payId,
        showName = showName
    }
    local tgaData = {}
    self:DoBuy(rechargeData,tgaData)
end

--* 后台活动商品直购类型
--* 充值参数格式:welfareId(计费点-礼包表refId)|type(3-后台活动礼包)|activityId&pageId&entryId
--local _IdFmtActivity = "#a1#|3|#a2#&#a3#&#a4#"
function LxPayCtrl:BuyActivityGift(params)
    local activityId = params.activityId
    local pageId = params.pageId
    local entryId = params.entryId
    local welfareRefId = params.welfareRefId
    local discountWelfareRefId, discountItemRefId = CtrlCenter.Item:GetPayDiscountData(welfareRefId)
    if discountWelfareRefId then
        welfareRefId = discountWelfareRefId
    end

    local payId = params.payId
    if payId == nil then
        payId = string.replace(_PayIdFmtEnums.Activity, welfareRefId, activityId, pageId, entryId, discountItemRefId or 0)
    end

    local showName = params.showName and params.showName or ""
    local rechargeData = {
        activityId = activityId,
        pageId = pageId,
        entryId = entryId,
        welfareRefId = welfareRefId,
        payType = 3,
        payId = payId,
        showName = showName,
    }
    local tgaData = {}
    self:DoBuy(rechargeData,tgaData)
end

