function LxPayCtrl:GetPayCurrency()
    return gLxSdkImpl:CallMethod(SdkMethod.GetCurrency)
end

function LxPayCtrl:GetPayCurrencyName(currency)
    local data = self:GetCurrencyData(currency)
    return data and data.showName or ""
end

function LxPayCtrl:GetPayCurrencySymbol(currency)
    local data = self:GetCurrencyData(currency)
    return data and data.symbol or ""
end

---@return V_WelfareActivitiesSymbolRef
function LxPayCtrl:GetCurrencyData(currency)
    local _currencyTopPayPointDatas = self._currencyTopPayPointDatas
    if not _currencyTopPayPointDatas then
        _currencyTopPayPointDatas = {}
        for k,v in pairs(GameTable.WelfareActivitiesSymbolRef) do
            _currencyTopPayPointDatas[v.type] = v
        end
        self._currencyTopPayPointDatas = _currencyTopPayPointDatas
    end
    return self._currencyTopPayPointDatas[currency]
end

---显示的价格，通过该接口获取
function LxPayCtrl:GetWelfarePayNumShowStr(welfareRefId)
    local discountWelfareRefId, discountItemRefId = CtrlCenter.Item:GetPayDiscountData(welfareRefId)
    if discountWelfareRefId then
        welfareRefId = discountWelfareRefId
    end

    local welfare = GameTable.WelfareActivitiesGiftRef[welfareRefId]
    if not welfare then
        if LOG_INFO_ENABLED then
            print(">>>-----------")
            LogError(">>>>>>>礼包表中不存在 refId="..tostring(welfareRefId))
        end
        return ""
    end

    local payPointRef = GameTable.WelfareActivitiesPayPointRef[welfare.payPoint]
    if not payPointRef then
        if LOG_INFO_ENABLED then
            print(">>>-----------")
            LogError(">>>>>>>计费点表中不存在 refId="..tostring(welfare.payPoint))
        end
        return ""
    end
    local currency = self:GetPayCurrency()
    local data = self:GetCurrencyData(currency)
    if not data then return "" end
    local valueName = data.name
    local symbolShow = data.symbolShow
    local fmt = symbolShow == 2 and "#a2##a1#" or "#a1##a2#"

    local localPrice = gLxSdkImpl:CallMethod(SdkMethod.GetLocalPrice, payPointRef)
    if not localPrice then
        localPrice = payPointRef[valueName] or 0
    end
    local str = string.replace(fmt, data.symbol, localPrice)
    return str
end

---价格对应现金券价值
---@return string
function LxPayCtrl:_InnerGetWelfareCastItemValue(welfareRefId)
    local welfare = GameTable.WelfareActivitiesGiftRef[welfareRefId]
    if not welfare then
        if LOG_INFO_ENABLED then
            print(">>>-----------")
            LogError(">>>>>>>礼包表中不存在 refId="..tostring(welfareRefId))
        end
        return 0
    end

    local payPointRef = GameTable.WelfareActivitiesPayPointRef[welfare.payPoint]
    if not payPointRef then
        if LOG_INFO_ENABLED then
            print(">>>-----------")
            LogError(">>>>>>>计费点表中不存在 refId="..tostring(welfare.payPoint))
        end
        return 0
    end
    return payPointRef.cashItem
end

---价格对应字符串
---@return string
function LxPayCtrl:_InnerGetWelfarePayValueStr(welfareRefId, currency)
    local welfare = GameTable.WelfareActivitiesGiftRef[welfareRefId]
    if not welfare then
        if LOG_INFO_ENABLED then
            print(">>>-----------")
            LogError(">>>>>>>礼包表中不存在 refId="..tostring(welfareRefId))
        end
        return
    end

    local payPointRef = GameTable.WelfareActivitiesPayPointRef[welfare.payPoint]
    if not payPointRef then
        if LOG_INFO_ENABLED then
            print(">>>-----------")
            LogError(">>>>>>>计费点表中不存在 refId="..tostring(welfare.payPoint))
        end
        return
    end

    local localPrice = gLxSdkImpl:CallMethod(SdkMethod.GetLocalPrice, payPointRef)
    if not localPrice then
        return localPrice
    end

    if not currency then
        currency = self:GetPayCurrency()
    end
    local data = self:GetCurrencyData(currency)
    if not data then return end
    local valueName = data.name
    local str = payPointRef[valueName]
    return str
end

---返回价格数字
---@return number
function LxPayCtrl:GetWelfarePayValue(welfareRefId, currency)
    local discountWelfareRefId, discountItemRefId = CtrlCenter.Item:GetPayDiscountData(welfareRefId)
    if discountWelfareRefId then
        welfareRefId = discountWelfareRefId
    end
    local str = self:_InnerGetWelfarePayValueStr(welfareRefId, currency)
    if not str then return 0 end
    local num = tonumber(str) or 0
    return num
end

