function LxPayCtrl:OnCreateOrderOk(uniqueId, orderId, sdkSign, jParameter)
    if string.isempty(uniqueId) then return end
    if uniqueId == ModuleCenter.Pay.currentCreateOrderUniqueId then
        ModuleCenter.Pay.currentCreateOrderUniqueId = nil
    end
    local createOrderData = {}
    createOrderData.uniqueId = uniqueId
    createOrderData.orderId = orderId
    createOrderData.sdkSign = sdkSign
    createOrderData.jParameter = jParameter
    if gLxSdkImpl then
        gLxSdkImpl:CallMethod(SdkMethod.CreateOrderOk,  createOrderData)
    end
end

function LxPayCtrl:IsOrderRequesting(uniqueId)
    return ModuleCenter.Pay.currentCreateOrderUniqueId == uniqueId
end

function LxPayCtrl:StartCreateOrder(params, uniqueId)
    ModuleCenter.Pay.currentCreateOrderUniqueId = uniqueId
    HandlerCenter.Pay:CreateOrderReq(params,uniqueId)
end

return LxPayCtrl